using System.Numerics;
using System.Runtime.CompilerServices;
using System.Runtime.InteropServices;

namespace MinMax;

public static class RangeCalculator
{
    /// <summary>
    /// Returns the minimum and maximum values in <paramref name="values"/>.
    /// Uses SIMD vectorization to process multiple elements per cycle.
    /// </summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static (float Min, float Max) FindMinMax(ReadOnlySpan<float> values)
    {
        if (values.Length == 0)
            throw new ArgumentException("Span must not be empty.");

        if (!Vector.IsHardwareAccelerated || values.Length < Vector<float>.Count)
            return FindMinMaxScalar(values);

        ref float start = ref MemoryMarshal.GetReference(values);
        int vecCount = Vector<float>.Count;

        var vMin = new Vector<float>(values);
        var vMax = vMin;

        // Process two vectors per iteration to improve ILP
        int i = vecCount;
        int limit = values.Length - (vecCount * 2 - 1);
        for (; i < limit; i += vecCount * 2)
        {
            var v0 = new Vector<float>(values.Slice(i));
            var v1 = new Vector<float>(values.Slice(i + vecCount));
            vMin = Vector.Min(vMin, Vector.Min(v0, v1));
            vMax = Vector.Max(vMax, Vector.Max(v0, v1));
        }

        // Handle remaining full vectors
        for (; i <= values.Length - vecCount; i += vecCount)
        {
            var v = new Vector<float>(values.Slice(i));
            vMin = Vector.Min(vMin, v);
            vMax = Vector.Max(vMax, v);
        }

        // Reduce vectors to scalars
        float min = vMin[0];
        float max = vMax[0];
        for (int j = 1; j < vecCount; j++)
        {
            if (vMin[j] < min) min = vMin[j];
            if (vMax[j] > max) max = vMax[j];
        }

        // Handle trailing elements
        for (; i < values.Length; i++)
        {
            float val = Unsafe.Add(ref start, i);
            if (val < min) min = val;
            if (val > max) max = val;
        }

        return (min, max);
    }

    private static (float Min, float Max) FindMinMaxScalar(ReadOnlySpan<float> values)
    {
        float min = values[0];
        float max = values[0];
        for (int i = 1; i < values.Length; i++)
        {
            if (values[i] < min) min = values[i];
            if (values[i] > max) max = values[i];
        }
        return (min, max);
    }
}

